import psycopg2
import sys

def connect_to_db():
    try:
        conn = psycopg2.connect(
            host="your_host",
            database="your_database",
            user="your_user",
            password="your_password"
        )
        return conn
    except Exception as e:
        print(f"Error connecting to the database: {e}")
        sys.exit(1)

def create_extension(conn, extension_name):
    try:
        cursor = conn.cursor()
        query = f"CREATE EXTENSION IF NOT EXISTS {extension_name};"
        cursor.execute(query)
        conn.commit()
        print(f"Extension '{extension_name}' created.")
    except Exception as e:
        print(f"Error creating extension '{extension_name}': {e}")

def main():
    if len(sys.argv) < 2:
        print("Usage: python script.py extension_name")
        sys.exit(1)

    conn = connect_to_db()

    extension_name = sys.argv[1]
    create_extension(conn, extension_name)

if __name__ == "__main__":
    main()